### Frontend (React)
First, we'll set up a React component to display and manage rooms. Here’s a simple `RoomList` component:

```jsx
import React, { useState, useEffect } from 'react';
import axios from 'axios';

const RoomList = () => {
  const [rooms, setRooms] = useState([]);

  useEffect(() => {
    fetchRooms();
  }, []);

  const fetchRooms = async () => {
    const response = await axios.get('/api/rooms');
    setRooms(response.data);
  };

  const addRoom = async (room) => {
    const response = await axios.post('/api/rooms', room);
    setRooms([...rooms, response.data]);
  };

  const updateRoom = async (id, updatedRoom) => {
    const response = await axios.put(`/api/rooms/${id}`, updatedRoom);
    setRooms(rooms.map(room => room._id === id ? response.data : room));
  };

  const deleteRoom = async (id) => {
    await axios.delete(`/api/rooms/${id}`);
    setRooms(rooms.filter(room => room._id !== id));
  };

  return (
    <div>
      <h1>Room Management System</h1>
      <button onClick={fetchRooms}>Fetch Rooms</button>
      <ul>
        {rooms.map(room => (
          <li key={room._id}>
            {room.name} - {room.capacity}
            <button onClick={() => updateRoom(room._id, { name: 'Updated Room', capacity: 20 })}>Update</button>
            <button onClick={() => deleteRoom(room._id)}>Delete</button>
          </li>
        ))}
      </ul>
      <form onSubmit={(e) => {
        e.preventDefault();
        const newRoom = { name: e.target.roomName.value, capacity: parseInt(e.target.capacity.value) };
        addRoom(newRoom);
        e.target.reset();
      }}>
        <input type="text" placeholder="Room Name" name="roomName" />
        <input type="number" placeholder="Capacity" name="capacity" />
        <button type="submit">Add Room</button>
      </form>
    </div>
  );
};

